mapper.select:
SELECT id, name, description, category, poster_url, venue, status, create_time, update_time
FROM `show`
WHERE id = #{id}

SELECT id, name, description, category, poster_url, venue, status, create_time, update_time FROM `show`
AND status = #{status} AND name LIKE CONCAT('%', #{name}, '%') AND category LIKE CONCAT('%', #{category}, '%') AND venue LIKE CONCAT('%', #{venue}, '%')
ORDER BY create_time DESC LIMIT #{size} OFFSET #{offset}
